const fs=require("fs");function slugify(s){return s?s.toString().toLowerCase().trim().replace(/\s+/g,"-").replace(/[채횆횪찼창찾채책]/g,"a").replace(/[철횜챵처척천철첩]/g,"o").replace(/[책횇]/g,"a").replace(/[^\w-]/g,"").replace(/--+/g,"-").replace(/^-+/,"").replace(/-+$/,""):""}const data=JSON.parse(fs.readFileSync("companies_data.json","utf8")),companies=data.results||[],slugs={};companies.forEach(s=>{const e=slugify(s.nimi);slugs[e]||(slugs[e]=[]),slugs[e].push(s.nimi)});for(const s in slugs)slugs[s].length>1&&console.log(`Conflict for slug "${s}":`,slugs[s]);slugs.mediazoo?console.log('Companies matching "mediazoo":',slugs.mediazoo):console.log('No company matches "mediazoo"');